   const computedStatus = context?.Form?.InspectionPage?.ComputedInspectionStatus?.Value || "";

   // Check if the status is a terminal status (timer should stop)
   const isTerminalStatus = ["Completed", "CGI", "Refused", "Fail", "Failed"]
       .some(status => computedStatus.includes(status));

   // Calculate active days
   if (createdDate) {
       // Convert strings to Date objects
       const created = new Date(createdDate);

       // Use the appropriate end date - either status date for terminal statuses or current date
       const endDate = isTerminalStatus && currentStatusDate ? 
           new Date(currentStatusDate) : new Date();

